UPDATE `object_validations` SET  `trigger_code` = 'import datetime\nnow = datetime.datetime.now()\nnow_time = datetime.datetime.now().date()\nallow_start_date = (now - datetime.timedelta(days=2, hours=0, minutes=0, seconds=0)).date()\nallow_end_date = (now + datetime.timedelta(days=2, hours=0, minutes=0, seconds=0)).date()\nif type(instance.call_date) == datetime.date:\n	call_date = instance.call_date\nelse:\n	call_date = datetime.datetime.strptime(instance.call_date, \'%Y-%m-%d\').date()\nif call_date < allow_start_date:\n	message = \'仅可创建2天以内拜访\'\n	raise create_validation_trigger_rule_errors(message)\nif call_date > now_time:\n	message = \'不能创建未来的拜访\'\n	raise create_validation_trigger_rule_errors(message)' WHERE (`id` = 'hxf4ef70-e980-11e9-b9aa-0298a739dec0');

